import (
	context "context"
	ssego "github.com/fern-api/sse-go"
	ssegoclient "github.com/fern-api/sse-go/client"
)

client := ssegoclient.NewClient()
response, err := client.Completions.StreamWithoutTerminator(
	context.TODO(),
	&ssego.StreamCompletionRequestWithoutTerminator{
		Query: "query",
	},
)

